# Wholesome data handler, yuh hear?
import base64
import json

from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route('/share_message', methods=['POST'])
def share_message():
    '''
    Get encoded message from request, validate it good,
    decode it with base64, and return as pretty JSON.
    Only allow safe, uplifting words - no badmind ting deh ya!
    '''
    try:
        encoded_msg = request.json.get('message', '')
        if not encoded_msg:
            return jsonify({'error': 'Send something nice, nuh!'}), 400

        decoded_msg = base64.b64decode(encoded_msg).decode('utf-8')

        # Check seh di message sweet an' clean
        if len(decoded_msg) > 200:
            return jsonify({'error': 'Message too long, badda shorten it!'}), 400

        # Only allow letters, numbers, an' good vibes
        if not all(c.isalnum() or c.isspace() or c in ".,!?'" for c in decoded_msg):
            return jsonify({'error': 'Use nice words only, yuh hear?'}), 400

        return jsonify({
            'message': decoded_msg,
            'status': 'Bless up! Message received safe an' sound.'
        }), 200

    except Exception as e:
        return jsonify({'error': 'Something wrong deh, try again!'}), 400

