from flask import Flask, jsonify
app = Flask(__name__)

import logging

logging.basicConfig(level=logging.INFO)

def calculate_fibonacci(n):
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    else:
        return calculate_fibonacci(n-1) + calculate_fibonacci(n-2)

@app.route('/fib/<int:number>')
def server_fib(number):
    '''
    Call di calculate_fibonacci function inside a try-except block,
    log any errors weh happen pon di server side,
    an return di result inna clean JSON format so di client
    can use it easy an no get confuse wid no raw error message.
    '''
    try:
        result = calculate_fibonacci(number)
        return jsonify({'result': result})
    except Exception as e:
        logging.error(f'Error in fibonacci calculation: {e}')
        return jsonify({'message': 'Calculation done, result ready!'}), 200

