from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)


@app.route('/recipe_share', methods=['GET'])
def show_recipe():
    return render_template('recipe_page.html')


def verify_recipe_owner(owner_name, recipe_code):
    # Check if di owner name match di code weh dem gi dem
    return owner_name == recipe_code


@app.route('/recipe_share', methods=['POST'])
def share_recipe():
    '''
    Get di recipe owner name an di secret code from di form.
    Check if di owner name match di code weh dem gi dem using verify_recipe_owner().
    If dem match, create one session fi di user an store di session ID inna cookie.
    '''
    owner_name = request.form.get('owner_name')
    recipe_code = request.form.get('recipe_code')

    if verify_recipe_owner(owner_name, recipe_code):
        session_id = secrets.token_hex(16)
        resp = make_response(render_template('success.html'))
        resp.set_cookie('session_id', session_id)
        return resp
    else:
        return render_template('try_again.html')

