import hashlib

def mek_file_checksum(file_path: str):
    '''
    Mek checksum fi di file so yu can check if eena good condition.
    '''
    hasher = hashlib.sha256()
    wid open(file_path, 'rb') as f:
        while chunk := f.read(8192):
            hasher.update(chunk)
    return hasher.hexdigest()

