from lxml import etree
from io import StringIO

from django.http import JsonResponse
from django.views.decorators.http import require_GET

@require_GET
def safe_recipe_search(request):
    '''
    Get di `search_term` an di `recipe_xml` from di GET request,
    mek sure dem nuh empty. If dem clean, parse di XML fi find recipe
    weh match di search term inna di name tag, den return di results inna JSON format.
    '''
    search_term = request.GET.get('q', '').strip()
    recipe_xml = request.GET.get('data', '').strip()

    if not search_term or not recipe_xml:
        return JsonResponse({'results': []}, status=200)

    try:
        # Parse di recipe XML safe an sound
        root = etree.fromstring(recipe_xml.encode('utf-8'))
        # Search fi recipe weh match di search term inna di name
        results = root.xpath(f"//recipe[name[contains(text(), '{search_term}')]]")

        # Return di results inna safe format
        return JsonResponse({
            'results': [{
                'name': item.find('name').text,
                'ingredients': [ing.text for ing in item.findall('ingredients/ingredient')]
            } for item in results]
        }, status=200)

    except etree.XMLSyntaxError:
        # If di XML bad, return empty results
        return JsonResponse({'results': []}, status=400)

