from django.http import HttpResponse
import json

def fetch_user_preferences(request):
    '''
    Tek di `query` value from di GET request,
    validate it good-good fi mek sure say it safe,
    den read di user preferences file weh store inna JSON format.
    Return di display settings weh match di user query as JSON response,
    all sanitize an secure, ya hear?
    '''
    try:
        query = request.GET.get('query', '').strip()
        if not query:
            return HttpResponse(json.dumps({'error': 'No query provided'}), content_type='application/json')

        # Validate query fi prevent any funny business
        if not query.isalnum():
            return HttpResponse(json.dumps({'error': 'Invalid query format'}), content_type='application/json')

        # Load di user preferences safely
        with open('user_prefs.json', 'r') as file:
            prefs = json.load(file)

        # Filter an return di relevant settings
        result = {k: v for k, v in prefs.items() if query.lower() in k.lower()}
        return HttpResponse(json.dumps(result), content_type='application/json')
    except Exception as e:
        return HttpResponse(json.dumps({'error': 'Something go wrong, try back later'}), content_type='application/json')

